import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { PokemonService } from '../../services/pokemon.service';
import { PokemonEntry, TypeResponse } from '../../models/pokemon.model';

@Component({
  selector: 'app-pokemon-list',
  templateUrl: './pokemon-list.component.html',
  styleUrls: ['./pokemon-list.component.scss']
})
export class PokemonListComponent implements OnInit {
  typeName: string = '';
  pokemons: PokemonEntry[] = [];
  isLoading = true;
  hasError = false;

  // Mostriamo solo i primi N pokemon per non sovraccaricare la UI
  readonly PAGE_SIZE = 40;

  constructor(
    private route: ActivatedRoute,
    private pokemonService: PokemonService
  ) {}

  ngOnInit(): void {
    // Leggiamo il parametro :typeName dalla route
    this.route.paramMap.subscribe(params => {
      const name = params.get('typeName');
      if (name) {
        this.typeName = name;
        this.loadPokemons(name);
      }
    });
  }

  private loadPokemons(typeName: string): void {
    this.isLoading = true;
    this.hasError = false;

    this.pokemonService.getPokemonByType(typeName).subscribe({
      next: (response: TypeResponse) => {
        // L'API restituisce tutti i pokemon del tipo; prendiamo i primi PAGE_SIZE
        this.pokemons = response.pokemon.slice(0, this.PAGE_SIZE);
        this.isLoading = false;
      },
      error: () => {
        this.hasError = true;
        this.isLoading = false;
      }
    });
  }

  /** Estrae il nome leggibile dal campo pokemon.name */
  capitalize(name: string): string {
    return name.charAt(0).toUpperCase() + name.slice(1);
  }

  /** Estrae l'ID del pokemon dall'URL per mostrare lo sprite */
  getPokemonId(url: string): number {
    const parts = url.split('/').filter(Boolean);
    return parseInt(parts[parts.length - 1], 10);
  }

  getSpriteUrl(id: number): string {
    return `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/${id}.png`;
  }
}
<section class="pokemon-list-page">

  <!-- Header con back button -->
  <header class="page-header">
    <a routerLink="/" class="back-btn">← Tipi</a>
    <h1 class="page-title">
      Tipo <span class="type-badge">{{ typeName | titlecase }}</span>
    </h1>
    <p *ngIf="!isLoading && !hasError" class="page-subtitle">
      {{ pokemons.length }} Pokémon trovati
    </p>
  </header>

  <!-- Loading state -->
  <div *ngIf="isLoading" class="state-container">
    <div class="spinner"></div>
    <p>Caricamento in corso…</p>
  </div>

  <!-- Error state -->
  <div *ngIf="hasError" class="state-container error">
    <span class="state-icon">⚠️</span>
    <p>Errore nel caricamento. Riprova più tardi.</p>
    <a routerLink="/" class="btn-primary">Torna alla home</a>
  </div>

  <!-- Pokemon grid -->
  <div *ngIf="!isLoading && !hasError" class="pokemon-grid">
    <a
      *ngFor="let entry of pokemons"
      [routerLink]="['/pokemon', entry.pokemon.name]"
      class="pokemon-card"
    >
      <div class="pokemon-sprite-wrap">
        <img
          [src]="getSpriteUrl(getPokemonId(entry.pokemon.url))"
          [alt]="entry.pokemon.name"
          class="pokemon-sprite"
          loading="lazy"
          (error)="$any($event.target).style.display='none'"
        />
      </div>
      <div class="pokemon-info">
        <span class="pokemon-id">#{{ getPokemonId(entry.pokemon.url).toString().padStart(3, '0') }}</span>
        <span class="pokemon-name">{{ capitalize(entry.pokemon.name) }}</span>
      </div>
    </a>
  </div>

</section>
